using Microsoft.AspNetCore.Mvc; using SchoolEnterprise.Helpers; using SchoolEnterprise.Models.ViewModels; using SchoolEnterprise.Repositories; using SchoolEnterprise.Services;
namespace SchoolEnterprise.Controllers; [RoleGuard("Admin","Secretary")] public class RecordsController(StudentRecordRepository repo, ClassOrderingService ordering, AuditService audit):Controller{ [HttpGet] public IActionResult Edit(int id){var r=repo.GetById(id); if(r==null) return NotFound(); return View(new StudentRecordEditVm{StudentRecordId=r.StudentRecordId,AcademicYear=r.AcademicYear,Grade=r.Grade,Section=r.Section,RollNumber=r.RollNumber});} [HttpPost] public IActionResult Edit(StudentRecordEditVm vm){var r=repo.GetById(vm.StudentRecordId); if(r!=null){r.AcademicYear=vm.AcademicYear;r.Grade=vm.Grade;r.Section=vm.Section;r.RollNumber=vm.RollNumber;repo.Update(r);audit.Log("تعديل سجل سنوي",$"{vm.StudentRecordId}");} return RedirectToAction("Index","Students");} [HttpGet] public IActionResult Transfer(int id)=>View(new TransferStudentVm{StudentRecordId=id}); [HttpPost] public IActionResult Transfer(TransferStudentVm vm){var r=repo.GetById(vm.StudentRecordId); if(r!=null){r.ClassRoomId=vm.TargetClassRoomId;repo.Update(r);audit.Log("نقل طالب",$"{vm.StudentRecordId}");} return RedirectToAction("Index","Students");} public IActionResult Archive(){var all=repo.GetAll(); foreach(var r in all.Where(x=>!x.IsCurrent)){r.IsArchived=true; repo.Update(r);} return View(all.Where(x=>x.IsArchived));} public IActionResult ReorderClass(int classId){ordering.Reorder(classId); audit.Log("إعادة ترتيب",$"{classId}"); return RedirectToAction("Students","Classes",new{id=classId});}}
